from collections import Counter

def detect_running_headers_footers(pages: list[str], threshold: float = 0.5) -> set[str]:
    """
    Return lines that appear in more than `threshold` fraction of pages —
    these are likely running headers or footers.
    """
    n_pages = len(pages)
    line_counts: Counter = Counter()
    for page_text in pages:
        # Count each unique line once per page (not total frequency)
        for line in set(page_text.splitlines()):
            stripped = line.strip()
            if stripped:
                line_counts[stripped] += 1

    # Lines appearing in > threshold fraction of pages are boilerplate
    return {
        line for line, count in line_counts.items()
        if count / n_pages > threshold
    }

def strip_running_elements(pages: list[str]) -> list[str]:
    boilerplate = detect_running_headers_footers(pages)
    cleaned = []
    for page_text in pages:
        lines = [
            l for l in page_text.splitlines()
            if l.strip() not in boilerplate
        ]
        cleaned.append("\n".join(lines))
    return cleaned
